const rows = (name) => {
  let items;
  try { items = $(name).all(); } catch (e) { return []; }
  if (!items || !items.length) return [];
  const out = [];
  for (const it of items) {
    const j = it && it.json;
    if (j == null) continue;
    if (Array.isArray(j)) out.push(...j);
    else if (Array.isArray(j.data)) out.push(...j.data);
    else if (typeof j === 'object' && Object.keys(j).length) out.push(j);
  }
  return out;
};
const NL = String.fromCharCode(10);
const num = (v) => (parseFloat(v) || 0);
const tick = (ok) => ok ? '✅' : '⏳';

const gateRows = rows('Fetch Gate Tracker');
const mrrRows = rows('Fetch Supplement MRR');
const gate = gateRows[0] || {};

const totalMrr = mrrRows.reduce((s, r) => s + num(r.mrr_gbp), 0);
const kits = num(gate.total_kits_sold);
const subs = num(gate.active_sub_count);
const optins = num(gate.fm_list_optins);
const conv = (gate.kit23_to_sub_conversion_pct == null || gate.kit23_to_sub_conversion_pct === '') ? '—' : gate.kit23_to_sub_conversion_pct;

const mrrLines = mrrRows.length
  ? mrrRows.map(r => '  ' + (r.product_slug || '?') + ': ' + (r.active_subscribers || 0) + ' subs = £' + num(r.mrr_gbp).toFixed(2) + '/mo').join(NL)
  : '  (no active supplement subscriptions)';

const healthy = gateRows.length || mrrRows.length;

const lines = [
  'Andro Prime — Weekly KPI Digest',
  '================================',
  '',
  'KIT SALES',
  'Total kits sold: ' + kits,
  '',
  'FOUNDING-MEMBER LIST',
  'List opt-ins (non-cash): ' + optins,
  '',
  'SUPPLEMENTS',
  'Active subscribers: ' + subs,
  'MRR: £' + totalMrr.toFixed(2),
  '',
  mrrLines,
  '',
  'CONVERSION',
  'Kit 2/3 → supplement: ' + conv + '%',
  '',
  'GATE STATUS',
  'Gate 0A — 50 kits:    ' + tick(kits >= 50) + ' ' + kits + '/50',
  'Gate 0A — 25 supplement pre-orders: (tracked outside this digest)',
  'Gate 0C — MRR £1k:    ' + tick(totalMrr >= 1000) + ' £' + totalMrr.toFixed(0) + '/£1000',
  'Gate 0C — 30 subs:    ' + tick(subs >= 30) + ' ' + subs + '/30',
  '',
  'DATA SOURCES',
  'Gate tracker rows: ' + gateRows.length + ' | Supplement MRR rows: ' + mrrRows.length
];
if (!healthy) {
  lines.push('⚠ Both queries returned no data this week (pre-launch or empty views). Figures shown as zero — the pipeline still ran successfully.');
}

const body = lines.join(NL);
return [{ json: { subject: 'Andro Prime KPI — w/c ' + new Date().toLocaleDateString('en-GB'), body } }];
